import{createDOMElement}from"../display/model";import{ControlFlow}from"../utils/util";class SizePanel{static Sizes={"800x600":{w:800,h:600},"1920x1080":{w:1920,h:1080},"2560x1440":{w:2560,h:1440},"3840x2160":{w:3840,h:2160},"2480x3508":{w:2480,h:3508},"3508x2480":{w:3508,h:2480},"2550x3300":{w:2550,h:3300},"1080x1080":{w:1080,h:1080},custom:{title:"Custom…"}};#callback=()=>{};#active="800x600";#elmP=null;#elm=null;#customWidthEl=null;#customHeightEl=null;#selSize=null;constructor(elmP,callback){this.#elmP=elmP,this.#callback=callback,this.#elm=this.#elmP.querySelector("li#size_ctn"),this.#init()}#setSize(size){if("custom"==this.#active&&"custom"!=size)this.#customWidthEl.remove(),this.#customHeightEl.remove();else if("custom"!=this.#active&&"custom"==size){const[w,h]=this.#active.split("x").map(Number);this.#customWidthEl.value=w,this.#customHeightEl.value=h,this.#elm.appendChild(this.#customWidthEl),this.#elm.appendChild(this.#customHeightEl)}this.#callback({action:"setSize",size:"custom"!=size?size:this.#active}),this.#active=size}#init(){this.#build(),this.#eventListener()}#build(){this.#customWidthEl=createDOMElement({type:"input",attributes:{type:"number",placeholder:"W",min:"1",max:"9999",style:"width:52px"}}),this.#customHeightEl=createDOMElement({type:"input",attributes:{type:"number",placeholder:"H",min:"1",max:"9999",style:"width:52px"}}),this.#selSize=createDOMElement({type:"select",attributes:{name:"sel-size"}});for(const opt in SizePanel.Sizes){var op=SizePanel.Sizes[opt];this.#selSize.appendChild(createDOMElement({type:"option",attributes:{value:opt},text:op?.title?op.title:opt}))}this.#elm.appendChild(this.#selSize)}#eventListener(){this.#selSize.addEventListener("change",(()=>{const{value:value}=this.#selSize;this.#setSize(value)})),[this.#customWidthEl,this.#customHeightEl].forEach(((elm,idx,arr)=>{const handler=ControlFlow.debounce((e=>{this.#callback({action:"setSize",custom:{w:Number(arr[0].value),h:Number(arr[1].value)}})}),1e3);elm.addEventListener("input",handler)}))}}export{SizePanel};